	private static List<PhysicalProperties> normalizeInputRequirements(TupleExpr alternative, RuleKind kind,
			List<PhysicalProperties> inputRequirements, boolean opaque) {
		List<PhysicalProperties> safeRequirements = inputRequirements == null ? List.of() : inputRequirements;
		if (opaque && !MemoInputLayout.slots(alternative).isEmpty()) {
			throw new IllegalArgumentException("Atomic physical implementation "
					+ alternative.getClass().getSimpleName() + " contains optimizable memo inputs");
		}
		if (opaque) {
			if (!safeRequirements.isEmpty()) {
				throw new IllegalArgumentException(
						"Atomic physical applications cannot require child properties");
			}
			return List.of();
		}
		int inputCount = MemoInputLayout.slots(alternative).size();
		if (safeRequirements.isEmpty()) {
			return inputCount == 0 || kind == RuleKind.TRANSFORMATION
					? List.of()
					: Collections.nCopies(inputCount, PhysicalProperties.ANY);
		}
		if (safeRequirements.size() != inputCount) {
			throw new IllegalArgumentException("Input requirement count " + safeRequirements.size()
					+ " does not match input count " + inputCount + " for "
					+ alternative.getClass().getSimpleName());
		}
		return safeRequirements.stream()
				.map(requirement -> requirement == null ? PhysicalProperties.ANY : requirement)
				.toList();
	}

